import { useState } from 'react';
import AddFixture from '../fixture/addFixture';
import Fixture from '../../data/interfaces/fixture';
import FixtureItem from './fixture-item';

// You have to pass in the props and say that props evaluates to fixturesToShow which is of type Fixture[]
const FixtureList = (props : {fixturesToShow : Fixture[]}) => {

    const {fixturesToShow} = props;

    // useState is a hook. Must be first line of the function. 
    // useState(xxx) - xxx is the original collection
    // [fixtures,...] - fixtures is the current copy of it. This will get updated by using setFixture
    // [..., setFixture] - is a function used to update the fixtures array.
    const [fixtures, setFixture] = useState(fixturesToShow);   
    return(
        <>    
        <div className="row">
            <div className='col-1'></div>
            <div className='col-10'>
                <table className="table table-hover table-condensed table-responsive">
                    <thead>
                        <tr>
                            <th>Date</th>
                            <th>Result</th>
                            <th>Score</th>
                            <th>Opposition</th>
                            <th>H/A</th>                            
                            <th>Pts</th>
                        </tr>
                    </thead>
                    <tbody>
                        {fixtures.map(f => <FixtureItem key={f.id} fixture={f}/>)}
                    </tbody>
                </table>                          
            </div>
        </div>        
        {/* <AddFixture currentFixtures={fixtures} setFixtureIntoArray={setFixture}/> */}
        </>
    );
}
export default FixtureList;


